window.PRIMS_SCRIPT={START:e=>`Welcome to Prim's forest! We're starting at node ${e} to grow a Minimum Spanning Tree that connects everyone for the lowest cost.`,EXPLORING:e=>`We're at node ${e}. Let's look at all the available edges leading out to unvisited nodes.`,PICKING:(e,t,n)=>`Found it! The cheapest available edge connects ${e} to ${t} with a cost of ${n}. Let's add it to our tree!`,ALREADY_VISITED:e=>`Node ${e} is already in our tree, so we'll skip this edge to avoid making a loop.`,SUCCESS:e=>`Our spanning tree is complete! We've connected every node using the cheapest paths possible. Total cost: ${e}.`},window.KRUSKALS_SCRIPT={START:()=>`Let's build a Minimum Spanning Tree using Kruskal's method! First, we'll sort every single edge from cheapest to most expensive.`,CHECKING:(e,t,n)=>`Checking the edge between ${e} and ${t} with weight ${n}. Is it safe to add?`,ADDING:(e,t)=>`Yes! Node ${e} and ${t} are currently in different groups. Connecting them won't create a cycle. Added!`,SKIPPING:(e,t)=>`Wait! Node ${e} and ${t} are already connected through other paths. Adding this edge would create a cycle. Skip!`,SUCCESS:e=>`The forest has merged into a single tree! We've found the minimum cost to connect everything. Total cost: ${e}.`};